// src/core/test-runner.ts
init_patch_engine();
async function runPatchTest(test) {
  const { name, input, patches, expected } = test;
  try {
    const patchResult = await applyPatches(input, patches, "warn");
    const actual = patchResult.content;
    const passed = actual === expected;
    let diff;
    if (!passed) {
      diff = generateDiff(expected, actual, `test: ${name}`);
    }
    return {
      name,
      passed,
      actual,
      expected,
      diff,
      appliedPatches: patchResult.applied,
      warnings: patchResult.warnings,
      validationErrors: patchResult.validationErrors
    };
  } catch (error) {
    return {
      name,
      passed: false,
      actual: "",
      expected,
      error: error instanceof Error ? error.message : String(error),
      appliedPatches: 0,
      warnings: [],
      validationErrors: []
    };
  }
}
async function runTestSuite(suite) {
  const results = [];
  let passed = 0;
  let failed = 0;
  for (const test of suite.tests) {
    const result = await runPatchTest(test);
    results.push(result);
    if (result.passed) {
      passed++;
    } else {
      failed++;
    }
  }
  return {
    total: suite.tests.length,
    passed,
    failed,
    results
  };
}

// src/core/test-suite-parser.ts
init_js_yaml();
function parseTestSuite(yamlContent) {
  try {
    const parsed = load(yamlContent);
    if (!parsed || typeof parsed !== "object") {
      throw new Error("Test suite must be a YAML object");
    }
    return parsed;
  } catch (error) {
    if (error instanceof YAMLException) {
      throw new Error(`YAML parsing error: ${error.message}`);
    }
    throw error;
  }
}
function validateTestSuite(suite) {
  const errors = [];
  if (!suite.apiVersion) {
    errors.push({
      field: "apiVersion",
      message: "apiVersion is required"
    });
  } else if (suite.apiVersion !== "kustomark/v1") {
    errors.push({
      field: "apiVersion",
      message: `apiVersion must be "kustomark/v1", got "${suite.apiVersion}"`
    });
  }
  if (!suite.kind) {
    errors.push({
      field: "kind",
      message: "kind is required"
    });
  } else if (suite.kind !== "PatchTestSuite") {
    errors.push({
      field: "kind",
      message: `kind must be "PatchTestSuite", got "${suite.kind}"`
    });
  }
  if (!suite.tests) {
    errors.push({
      field: "tests",
      message: "tests is required"
    });
  } else if (!Array.isArray(suite.tests)) {
    errors.push({
      field: "tests",
      message: "tests must be an array"
    });
  } else if (suite.tests.length === 0) {
    errors.push({
      field: "tests",
      message: "tests array cannot be empty"
    });
  } else {
    suite.tests.forEach((test, index) => {
      const testErrors = validateTest(test, index);
      errors.push(...testErrors);
    });
    const nameErrors = validateTestNames(suite.tests);
    errors.push(...nameErrors);
  }
  return {
    valid: errors.length === 0,
    errors,
    warnings: []
  };
}
function validateTest(test, index) {
  const errors = [];
  const prefix = `tests[${index}]`;
  if (!test || typeof test !== "object") {
    errors.push({
      field: prefix,
      message: "test must be an object"
    });
    return errors;
  }
  const t = test;
  if (!t.name) {
    errors.push({
      field: `${prefix}.name`,
      message: "test name is required"
    });
  } else if (typeof t.name !== "string") {
    errors.push({
      field: `${prefix}.name`,
      message: "test name must be a string"
    });
  } else if (t.name.trim() === "") {
    errors.push({
      field: `${prefix}.name`,
      message: "test name cannot be empty"
    });
  }
  if (t.input === undefined) {
    errors.push({
      field: `${prefix}.input`,
      message: "test input is required"
    });
  } else if (typeof t.input !== "string") {
    errors.push({
      field: `${prefix}.input`,
      message: "test input must be a string"
    });
  }
  if (!t.patches) {
    errors.push({
      field: `${prefix}.patches`,
      message: "test patches is required"
    });
  } else if (!Array.isArray(t.patches)) {
    errors.push({
      field: `${prefix}.patches`,
      message: "test patches must be an array"
    });
  } else if (t.patches.length === 0) {
    errors.push({
      field: `${prefix}.patches`,
      message: "test patches array cannot be empty"
    });
  } else {
    t.patches.forEach((patch, patchIndex) => {
      if (!patch || typeof patch !== "object") {
        errors.push({
          field: `${prefix}.patches[${patchIndex}]`,
          message: "patch must be an object"
        });
      } else {
        const p = patch;
        if (!p.op) {
          errors.push({
            field: `${prefix}.patches[${patchIndex}].op`,
            message: "patch operation (op) is required"
          });
        } else if (typeof p.op !== "string") {
          errors.push({
            field: `${prefix}.patches[${patchIndex}].op`,
            message: "patch operation (op) must be a string"
          });
        }
      }
    });
  }
  if (t.expected === undefined) {
    errors.push({
      field: `${prefix}.expected`,
      message: "test expected output is required"
    });
  } else if (typeof t.expected !== "string") {
    errors.push({
      field: `${prefix}.expected`,
      message: "test expected output must be a string"
    });
  }
  return errors;
}
function validateTestNames(tests) {
  const errors = [];
  const seenNames = new Set;
  tests.forEach((test, index) => {
    if (!test || typeof test !== "object") {
      return;
    }
    const t = test;
    if (t.name && typeof t.name === "string") {
      if (seenNames.has(t.name)) {
        errors.push({
          field: `tests[${index}].name`,
          message: `duplicate test name "${t.name}" (test names must be unique within a suite)`
        });
      } else {
        seenNames.add(t.name);
      }
    }
  });
  return errors;
}

