function outputTemplateShow(result, options) {
  console.log(`Template: ${result.template.name}`);
  console.log(`ID: ${result.template.id}`);
  console.log(`Description: ${result.template.description}`);
  console.log(`Source: ${result.template.source}`);
  if (result.template.tags.length > 0) {
    console.log(`Tags: ${result.template.tags.join(", ")}`);
  }
  console.log(`
Files (${result.template.files.length}):`);
  for (const file of result.template.files) {
    console.log(`  - ${file}`);
  }
  if (result.variables.length > 0) {
    console.log(`
Variables (${result.variables.length}):`);
    for (const variable of result.variables) {
      console.log(`  - {{${variable.name}}}`);
      if (options.verbosity > 1) {
        console.log(`    Used in: ${variable.files.join(", ")}`);
      }
    }
    console.log(`
Provide variables when applying: --var ${result.variables[0]?.name}=value`);
  } else {
    console.log(`
No variables required.`);
  }
  console.log(`
Apply this template:`);
  console.log(`  kustomark template apply ${result.template.id} [output-dir]`);
}
function outputTemplateApply(result, options) {
  if (result.dryRun) {
    console.log(`Dry run: Preview of template application
`);
  }
  if (options.verbosity > 0) {
    console.log(`Template: ${result.template}`);
    console.log(`Output directory: ${result.outputDir}`);
    console.log("");
  }
  if (result.files.length > 0) {
    const verb = result.dryRun ? "Would create" : "Created";
    console.log(`${verb} ${result.files.length} file(s):`);
    for (const file of result.files) {
      console.log(`  ${result.dryRun ? "+" : "\u2713"} ${file}`);
    }
  }
  if (result.skipped.length > 0) {
    console.log(`
Skipped ${result.skipped.length} existing file(s):`);
    for (const file of result.skipped) {
      console.log(`  - ${file}`);
    }
    if (!result.dryRun) {
      console.log(`
Use --overwrite to replace existing files.`);
    }
  }
  if (options.verbosity > 0 && result.substitutions > 0) {
    console.log(`
Variable substitutions: ${result.substitutions}`);
  }
  if (result.dryRun) {
    console.log(`
No files were written (dry run mode).`);
    console.log("Remove --dry-run to apply the template.");
  } else if (result.files.length > 0) {
    console.log(`
Template applied successfully!`);
  }
}

