async function gatherMetadata() {
  const answers = await Ce({
    name: () => he({
      message: "Template name (kebab-case):",
      placeholder: "my-custom-template",
      validate: (value) => {
        if (!value || value.trim() === "") {
          return "Template name is required";
        }
        if (!/^[a-z0-9-]+$/.test(value)) {
          return "Template name must be kebab-case (lowercase letters, numbers, and hyphens)";
        }
      }
    }),
    description: () => he({
      message: "Template description:",
      placeholder: "A brief description of what this template does",
      validate: (value) => {
        if (!value || value.trim() === "") {
          return "Description is required";
        }
      }
    }),
    category: () => ve({
      message: "Template category:",
      options: [
        {
          value: "upstream-fork",
          label: "Upstream Fork",
          hint: "For consuming markdown from upstream sources"
        },
        {
          value: "documentation",
          label: "Documentation",
          hint: "For documentation pipeline templates"
        },
        {
          value: "skills",
          label: "Skills",
          hint: "For Claude Code skill customization"
        },
        {
          value: "custom",
          label: "Custom",
          hint: "For custom/other use cases"
        }
      ],
      initialValue: "custom"
    }),
    addAuthor: () => ye({
      message: "Add author information?",
      initialValue: false
    }),
    author: ({ results }) => results.addAuthor ? he({
      message: "Author name:",
      placeholder: "Your Name"
    }) : undefined,
    email: ({ results }) => results.addAuthor ? he({
      message: "Author email:",
      placeholder: "you@example.com",
      validate: (value) => {
        if (value && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
          return "Invalid email format";
        }
      }
    }) : undefined
  }, {
    onCancel: () => {
      throw new Error("cancelled");
    }
  });
  return {
    name: answers.name,
    description: answers.description,
    category: answers.category,
    author: typeof answers.author === "string" ? answers.author : undefined,
    email: typeof answers.email === "string" ? answers.email : undefined
  };
}
async function gatherVariables() {
  const variables = [];
  const addVariables = await ye({
    message: "Add template variables?",
    initialValue: true
  });
  if (!addVariables) {
    return variables;
  }
  let continueAdding = true;
  while (continueAdding) {
    Me(`Defining variable ${variables.length + 1}`);
    try {
      const variable = await Ce({
        name: () => he({
          message: "Variable name (SCREAMING_SNAKE_CASE):",
          placeholder: "MY_VARIABLE",
          validate: (value) => {
            if (!value || value.trim() === "") {
              return "Variable name is required";
            }
            if (!/^[A-Z][A-Z0-9_]*$/.test(value)) {
              return "Variable name must be SCREAMING_SNAKE_CASE (uppercase letters, numbers, and underscores)";
            }
            if (variables.some((v2) => v2.name === value)) {
              return "Variable name already exists";
            }
          }
        }),
        description: () => he({
          message: "Variable description:",
          placeholder: "Description of what this variable is used for",
          validate: (value) => {
            if (!value || value.trim() === "") {
              return "Description is required";
            }
          }
        }),
        type: () => ve({
          message: "Variable type:",
          options: [
            { value: "string", label: "String" },
            { value: "boolean", label: "Boolean" },
            { value: "number", label: "Number" },
            { value: "array", label: "Array" }
          ],
          initialValue: "string"
        }),
        required: () => ye({
          message: "Is this variable required?",
          initialValue: true
        }),
        addDefault: ({ results }) => !results.required ? ye({
          message: "Add a default value?",
          initialValue: false
        }) : undefined,
        defaultValue: ({ results }) => results.addDefault ? he({
          message: `Default value (${results.type ?? "string"}):`,
          placeholder: getPlaceholderForType(results.type ?? "string")
        }) : undefined
      }, {
        onCancel: () => {
          throw new Error("cancelled");
        }
      });
      variables.push({
        name: variable.name,
        description: variable.description,
        type: variable.type,
        required: variable.required,
        defaultValue: typeof variable.defaultValue === "string" ? variable.defaultValue : undefined
      });
      const continueResponse = await ye({
        message: "Add another variable?",
        initialValue: false
      });
      if (typeof continueResponse === "symbol") {
        break;
      }
      continueAdding = continueResponse;
    } catch (error) {
      if (error instanceof Error && error.message === "cancelled") {
        break;
      }
      throw error;
    }
  }
  return variables;
}
async function createTemplateStructure(outputPath, metadata, variables, _options) {
  const absolutePath = resolve16(outputPath);
  if (existsSync17(absolutePath)) {
    throw new Error(`Directory already exists: ${absolutePath}`);
  }
  mkdirSync4(absolutePath, { recursive: true });
  const filesDir = join16(absolutePath, "files");
  mkdirSync4(filesDir, { recursive: true });
  const createdFiles = [];
  const templateYaml = generateTemplateYaml(metadata, variables);
  const templateYamlPath = join16(absolutePath, "template.yaml");
  writeFileSync7(templateYamlPath, templateYaml, "utf-8");
  createdFiles.push("template.yaml");
  const readme = generateReadme(metadata, variables);
  const readmePath = join16(absolutePath, "README.md");
  writeFileSync7(readmePath, readme, "utf-8");
  createdFiles.push("README.md");
  const exampleConfig = generateExampleKustomarkConfig(variables);
  const exampleConfigPath = join16(filesDir, "kustomark.yaml");
  writeFileSync7(exampleConfigPath, exampleConfig, "utf-8");
  createdFiles.push("files/kustomark.yaml");
  const exampleMd = generateExampleMarkdown(variables);
  const exampleMdPath = join16(filesDir, "example.md");
  writeFileSync7(exampleMdPath, exampleMd, "utf-8");
  createdFiles.push("files/example.md");
  return {
    success: true,
    path: absolutePath,
    files: createdFiles
  };
}
function generateTemplateYaml(metadata, variables) {
  const template = {
    apiVersion: "kustomark/v1",
    kind: "Template",
    metadata: {
      name: metadata.name,
      description: metadata.description,
      category: metadata.category,
      tags: [metadata.category],
      author: metadata.author && metadata.email ? `${metadata.author} <${metadata.email}>` : metadata.author ? metadata.author : undefined,
      version: "1.0.0"
    },
    variables: variables.map((v2) => {
      const variable = {
        name: v2.name,
        description: v2.description,
        type: v2.type,
        required: v2.required
      };
      if (v2.defaultValue) {
        switch (v2.type) {
          case "boolean":
            variable.default = v2.defaultValue.toLowerCase() === "true";
            break;
          case "number":
            variable.default = Number.parseFloat(v2.defaultValue);
            break;
          case "array":
            variable.default = v2.defaultValue.split(",").map((s) => s.trim());
            break;
          default:
            variable.default = v2.defaultValue;
        }
      }
      return variable;
    }),
    files: [
      {
        src: "files/kustomark.yaml",
        dest: "kustomark.yaml",
        substitute: true
      },
      {
        src: "files/example.md",
        dest: "example.md",
        substitute: true
      }
    ]
  };
  let yamlContent = dump(template, {
    indent: 2,
    lineWidth: -1,
    noRefs: true
  });
  yamlContent += `
# Post-apply commands (optional)
`;
  yamlContent += `# Uncomment and customize as needed:
`;
  yamlContent += `#
`;
  yamlContent += `# postApply:
`;
  yamlContent += `#   - description: Initialize git repository
`;
  yamlContent += `#     command: git init
`;
  yamlContent += `#
`;
  yamlContent += `#   - description: Install dependencies
`;
  yamlContent += `#     command: npm install
`;
  return yamlContent;
}
